import{_ as t,o as e,c as s,a2 as i}from"./chunks/framework.M-AdQQii.js";const c=JSON.parse('{"title":"2.6 神之庭院","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 神之庭院是一个类似副本的地方，不可以唤出载具，不可以挂机。只能通过世界之脐来进入。是完成古代装备养成的重要地方。同时你如果要做某些任务，也需要你的主线剧情来到神之庭院。 玩家可以通过悉拉玛","frontmatter":{"title":"2.6 神之庭院","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 神之庭院是一个类似副本的地方，不可以唤出载具，不可以挂机。只能通过世界之脐来进入。是完成古代装备养成的重要地方。同时你如果要做某些任务，也需要你的主线剧情来到神之庭院。 玩家可以通过悉拉玛","outline":"deep"},"headers":[],"relativePath":"pve/2-6.md","filePath":"pve/2-6.md","lastUpdated":1782387794000}'),u={name:"pve/2-6.md"};function p(l,a,g,r,o,d){return e(),s("div",null,[...a[0]||(a[0]=[i('<h1 id="_2-6-神之庭院" tabindex="-1">2.6 神之庭院 <a id="s211-46041b64"></a> <a class="header-anchor" href="#_2-6-神之庭院" aria-label="Permalink to &quot;2.6 神之庭院 &lt;a id=&quot;s211-46041b64&quot;&gt;&lt;/a&gt;&quot;">​</a></h1><p>本节点为目录/结构标题，具体操作内容见其下级章节。</p><h2 id="_2-6-1-什么是神之庭院" tabindex="-1">2.6.1 什么是神之庭院 <a id="s212-6b8e2cf6"></a> <a class="header-anchor" href="#_2-6-1-什么是神之庭院" aria-label="Permalink to &quot;2.6.1 什么是神之庭院 &lt;a id=&quot;s212-6b8e2cf6&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>神之庭院是一个类似副本的地方，不可以唤出载具，不可以挂机。只能通过世界之脐来进入。是完成古代装备养成的重要地方。同时你如果要做某些任务，也需要你的主线剧情来到神之庭院。</p><h2 id="_2-6-2-怎么进入神之庭院" tabindex="-1">2.6.2 怎么进入神之庭院 <a id="s213-9f0399d0"></a> <a class="header-anchor" href="#_2-6-2-怎么进入神之庭院" aria-label="Permalink to &quot;2.6.2 怎么进入神之庭院 &lt;a id=&quot;s213-9f0399d0&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>玩家可以通过悉拉玛山脉东部的世界之脐的庭院之门来进入神之庭院。</p><p>注意：如果想要换称号或者敲鼓什么的，请在庭院外进行，进去后就不能进行这些操作了。</p><p>进入方法如图所示：</p><p>走向箭头指向的红框内的门按F，即可进入庭院。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2391.jpeg" alt="图示：2.6.2 怎么进入神之庭院" loading="lazy"></figure><h2 id="_2-6-3-庭院侦查分数的获得" tabindex="-1">2.6.3 庭院侦查分数的获得 <a id="s214-245a639a"></a> <a class="header-anchor" href="#_2-6-3-庭院侦查分数的获得" aria-label="Permalink to &quot;2.6.3 庭院侦查分数的获得 &lt;a id=&quot;s214-245a639a&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>最简单的方法当然是花1000 金请个大佬带你刷到6 阶段。（滑稽）</p><p>在图示的妖精NPC 处接取任务后，即可开始获得庭院侦查分数：</p><p>摘花、钓鱼、刷怪、参与击杀庭院BOSS 都可</p><p>以获得庭院侦查分数，其中击杀庭院BOSS 单次给</p><p>的分数最多，但是对比起单刷或者花钱，时间要多</p><p>很多。</p><p>（摘花、钓鱼、刷怪时都有概率获得庭院生命</p><p>体标本）</p><p>获得神之庭院侦查分数比不可少的东西就是：精灵的庇护不管你是自己刷怪还是混BOSS 还是请人刷都最好准备这个，在庇护期间刷怪获得的侦查分数会增加很多，并且可以在死亡时免除一次分数扣除。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2399.jpeg" alt="图示：2.6.3 庭院侦查分数的获得" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2400.jpeg" alt="图示：2.6.3 庭院侦查分数的获得" loading="lazy"></figure><h2 id="_2-6-4-精灵之庇护的获得" tabindex="-1">2.6.4 精灵之庇护的获得 <a id="s215-f8a911ef"></a> <a class="header-anchor" href="#_2-6-4-精灵之庇护的获得" aria-label="Permalink to &quot;2.6.4 精灵之庇护的获得 &lt;a id=&quot;s215-f8a911ef&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>提到刷庭院，庇护是避不开的。不过当然版本庇护获取非常容易，价格比较低廉。</p><p>庇护有3 种获得方式：</p><p>①自主制作</p><p>②拍卖行购买</p><p>③每周庭院侦查分数排名奖励</p><p>目前来说是不推荐第一种方式的，因为只要开始打庭院，就有排名参与奖，会补充一些庇护，而且庇护在拍卖行价格远低于其制作成本</p><h2 id="_2-6-5-庭院侦查等级奖励" tabindex="-1">2.6.5 庭院侦查等级奖励 <a id="s216-f0ca15e3"></a> <a class="header-anchor" href="#_2-6-5-庭院侦查等级奖励" aria-label="Permalink to &quot;2.6.5 庭院侦查等级奖励 &lt;a id=&quot;s216-f0ca15e3&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>一般来说推荐2、6、12 级再提交任务获得奖励。</p><p>奖励如下：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2406.jpeg" alt="图示：2.6.5 庭院侦查等级奖励" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2407.jpeg" alt="图示：2.6.5 庭院侦查等级奖励" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2408.jpeg" alt="图示：2.6.5 庭院侦查等级奖励" loading="lazy"></figure><h2 id="_2-6-6-每周庭院积分排名奖励" tabindex="-1">2.6.6 每周庭院积分排名奖励 <a id="s217-11895e8d"></a> <a class="header-anchor" href="#_2-6-6-每周庭院积分排名奖励" aria-label="Permalink to &quot;2.6.6 每周庭院积分排名奖励 &lt;a id=&quot;s217-11895e8d&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>参与奖：</p><p>查看排名及奖励方法如下：</p><p>鼠标左键①箭头指向红框位置后，鼠标左键②箭头指向红框位置，再将鼠标移动到③位置即可查看箱子内容，想查看什么级别的，就像鼠标移动到什么级别的箱子的图标上查看即可。</p><p>第一名的太初箱子会有一个成就（相当卷）。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2415.jpeg" alt="图示：2.6.6 每周庭院积分排名奖励" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2416.jpeg" alt="图示：2.6.6 每周庭院积分排名奖励" loading="lazy"></figure>',42)])])}const h=t(u,[["render",p]]);export{c as __pageData,h as default};
